import{_ as r,o as t,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G01: 公司歷史與創辦人研究 — 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3163_波若威/20260502/G01_公司歷史與創辦人研究.md","filePath":"審計報告庫/經營審計/3163_波若威/20260502/G01_公司歷史與創辦人研究.md"}'),l={name:"審計報告庫/經營審計/3163_波若威/20260502/G01_公司歷史與創辦人研究.md"};function n(i,a,s,h,g,_){return t(),e("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g01-公司歷史與創辦人研究-—-經營審計專家報告" tabindex="-1">G01: 公司歷史與創辦人研究 — 經營審計專家報告 <a class="header-anchor" href="#g01-公司歷史與創辦人研究-—-經營審計專家報告" aria-label="Permalink to &quot;G01: 公司歷史與創辦人研究 — 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司歷史背景、創辦人及其性格與價值觀為何？對公司目前文化及發展策略有何深層影響？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：波若威由吳國精1998年創立，屬人脈財務型創業。創辦人2024年逝世，集體接班尚穩，惟2025年本業利潤率5.4%仍偏低，治理形象因炒股案受損。</li><li><strong>風險評級</strong>：中高</li><li><strong>數據時效</strong>：截至2025年度</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B-（中偏弱）</strong>：營收27.79億(2023)→19.41億(2024,-30%)→22.26億(2025,+14.7%)。關鍵警訊：2024年營業利益-515萬（實質虧損），靠業外撐EPS 5.75；2025年營業利益1.2億（率5.4%），業外仍佔稅前淨利87%。創辦人逝世後接棒，惟炒股案汙點損治理形象。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="創辦人畫像" tabindex="-1">創辦人畫像 <a class="header-anchor" href="#創辦人畫像" aria-label="Permalink to &quot;創辦人畫像&quot;">​</a></h3><ul><li><strong>核心重點</strong>：吳國精（1950-2024），馬里蘭州立大學MBA，工研院財務室主任出身。1998年以5100萬創立波若威，以人脈募集陳有諒、鄭萬來等六大股東，屬人脈財務型創業。</li><li><strong>深度見解</strong>：創業前已投資美國Wavesplitter獲利，奠定「先投資再創業」路徑：技術靠跟隨、財務操作為核心競爭力。吳國精同掌台灣光罩，形成泛波若威集團。2024年5月因膽管癌逝世，享壽74歲。</li></ul><h3 id="三階段歷史" tabindex="-1">三階段歷史 <a class="header-anchor" href="#三階段歷史" aria-label="Permalink to &quot;三階段歷史&quot;">​</a></h3><ul><li><strong>核心重點</strong>：三個階段：1998-2010光纖跟隨者（日本FTTH）→2010-2022資料中心（MPO/MTP）→2023起AI供應鏈（800G/1.6T/CPO）。營收27.79億(2023)→19.41億(2024)→22.26億(2025)。</li><li><strong>深度見解</strong>：創辦人逝世與AI需求雙重重疊，公司在無強人領導下進入轉型，為最大不確定性。</li></ul><h3 id="治理韌性" tabindex="-1">治理韌性 <a class="header-anchor" href="#治理韌性" aria-label="Permalink to &quot;治理韌性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：董事長鄭萬來（永彰機電前總經理）+總經理黃裕文（交大光電所）雙核心。股東含國發基金、陳有諒，結構穩固。</li><li><strong>深度見解</strong>：關鍵風險在無人能複製吳國精的募資整合能力。黃裕文技術型執行者，鄭萬來傳統產業出身，資本市場魅力不足。吳國精生前因炒股案被判刑3年2月（逝世後公訴不受理），治理形象折損。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>創辦人逝世後的領導力真空風險</strong>：吳國精不僅是創辦人，更是「泛波若威集團」的靈魂人物，擅長跨產業資源整合（光罩+光通訊+IC設計）。他逝世後，波若威在矽光子/CPO等前瞻布局的對外策略合作談判能力恐弱化，尤其在與NVIDIA等國際大廠供應鏈對接時，缺乏同等級別的談判代表。</li><li><strong>本業獲利能力持續低迷的警訊</strong>：2024年全年營業利益為-515萬，2025年回升至1.2億但營業利益率僅約5.4%，遠低於2023年的8.7%。EPS 6.22創歷史新高的背後，是業外收益（匯兌、處分資產、金融資產評價）佔稅前淨利87.3%，核心本業貢獻極低。若新台幣匯率反轉或金融市場波動，獲利將顯著下滑。</li><li><strong>AI轉型進度與產能的地緣壓力</strong>：公司高度依賴中國中山廠生產，在中美科技戰持續升溫與供應鏈去中化壓力下，若AI客戶要求非中國產能，波若威可能面臨產能調整的過渡期陣痛。目前尚未看到明確的東南亞產能布局計劃。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>FinMind</strong>：TaiwanStockMonthRevenue (3163, 2023-01 ~ 2025-12) — 月營收明細</li><li><strong>FinMind</strong>：TaiwanStockFinancialStatements (3163, 2023Q1 ~ 2025Q4) — 季損益、EPS</li><li><strong>web_fetch</strong>：Browave官網公司沿革 (<a href="https://www.browave.com/Pages/8" target="_blank" rel="noreferrer">https://www.browave.com/Pages/8</a>)</li><li><strong>web_search</strong>：今周刊2001年報導「波若威的六大金主」— 創辦團隊背景</li><li><strong>web_search</strong>：吳國精逝世相關報導 (ETtoday, 2024/05; CNA, 2024/05)</li><li><strong>web_search</strong>：吳國精背景與工研院經歷 (今周刊, 2019/06)</li><li><strong>web_search</strong>：波若威2025年營運展望 (鉅亨網, 自由時報, 2025-2026)</li></ul>',19)])])}const u=r(l,[["render",n]]);export{c as __pageData,u as default};
